mapper.select:
select id, tenant_id, channel_code, channel_name, channel_type, target_endpoint, auth_type, config_json, receipt_policy, timeout_seconds, enabled, created_at, updated_at from batch.file_channel_config where tenant_id = #{tenantId} and is_deleted = false
and channel_code like concat('%', #{channelCode}, '%')
and channel_type = #{channelType}
and enabled = #{enabled}
order by id desc
limit #{pageRequest.pageSize} offset (#{pageRequest.pageNo} - 1) * #{pageRequest.pageSize}

select count(1)
from batch.file_channel_config
where tenant_id = #{tenantId}
  and is_deleted = false

    and channel_code like concat('%', #{channelCode}, '%')


    and channel_type = #{channelType}


    and enabled = #{enabled}

select *
from batch.file_channel_config
where tenant_id = #{tenantId}
  and is_deleted = false
  and channel_code = #{channelCode}
limit 1
